-- ============================================
-- Import Chinese administrative regions data
-- Source: dmfw.mca.gov.cn (Ministry of Civil Affairs)
-- 4-level: PROVINCE(2位) → CITY(6位) → DISTRICT(6位) → STREET(9位)
-- ============================================

TRUNCATE TABLE regions RESTART IDENTITY CASCADE;


-- Update parent_id: PROVINCE → MACRO_REGION
UPDATE regions r SET parent_id = m.id FROM regions m WHERE r.region_type = 'PROVINCE' AND m.region_type = 'MACRO_REGION' AND r.parent_code = m.code;

-- Update parent_id: CITY → PROVINCE
UPDATE regions r SET parent_id = p.id FROM regions p WHERE r.region_type = 'CITY' AND p.region_type = 'PROVINCE' AND r.parent_code = p.code;

-- Update parent_id: DISTRICT → CITY
UPDATE regions r SET parent_id = c.id FROM regions c WHERE r.region_type = 'DISTRICT' AND c.region_type = 'CITY' AND r.parent_code = c.code;

-- Update parent_id: DISTRICT → PROVINCE (municipalities, no city level)
UPDATE regions r SET parent_id = p.id FROM regions p WHERE r.region_type = 'DISTRICT' AND p.region_type = 'PROVINCE' AND r.parent_code = p.code AND r.parent_id IS NULL;

-- Update parent_id: STREET → DISTRICT
UPDATE regions r SET parent_id = d.id FROM regions d WHERE r.region_type = 'STREET' AND d.region_type = 'DISTRICT' AND r.parent_code = d.code;

-- Update parent_id: STREET → CITY (no district level)
UPDATE regions r SET parent_id = c.id FROM regions c WHERE r.region_type = 'STREET' AND c.region_type = 'CITY' AND r.parent_code = c.code AND r.parent_id IS NULL;

-- Update parent_id: STREET → PROVINCE (municipalities)
UPDATE regions r SET parent_id = p.id FROM regions p WHERE r.region_type = 'STREET' AND p.region_type = 'PROVINCE' AND r.parent_code = p.code AND r.parent_id IS NULL;
